array.string:
export PATH="$HOME/.local/bin:/usr/local/bin:/opt/homebrew/bin:$PATH";
cd /Users/tm/Projects/Claude/ResearchMan;
LOG=/tmp/researchman-auto.log;
echo "===== Run start: $(date) =====" >> $LOG;
node scripts/auto-research-cc.mjs >> $LOG 2>&1;
node scripts/self-heal-thumbnails.mjs >> $LOG 2>&1;
git add data/cases.json public/thumbnails/ >> $LOG 2>&1;
if git diff --quiet HEAD; then
  echo "変更なし（新規事例なし）: $(date)" >> $LOG;
else
  git commit -m "Auto research: $(date '+%Y-%m-%d')" >> $LOG 2>&1;
  if git push >> $LOG 2>&1; then
    if node scripts/verify-deploy.mjs >> $LOG 2>&1; then
      echo "反映まで確認OK: $(date)" >> $LOG;
      node scripts/send-mail.mjs >> $LOG 2>&1;
      node scripts/notify-line.mjs >> $LOG 2>&1;
    else
      echo "push成功だが反映未確認（時間切れ）: $(date)" >> $LOG;
    fi;
  else
    echo "push失敗（pre-push監査で中止の可能性）。コミットはローカル残存。要手動対応: $(date)" >> $LOG;
  fi;
fi;
echo "Completed: $(date)" >> $LOG
